<?php
namespace App\Http\Controllers;
use App\Enums\PrintOrderStatus; use App\Http\Requests\StorePrintOrderRequest; use App\Jobs\SimulatePrintJob; use App\Models\PrintOrder; use App\Services\LockerAssignmentService; use App\Services\PickupCodeService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; use Illuminate\Support\Str; use Inertia\Inertia; use Inertia\Response; use RuntimeException;
class PrintOrderController extends Controller { public function create(): Response{return Inertia::render('orders/create',['maxUploadMb'=>config('queueless.upload_max_kilobytes')/1024,'simulation'=>config('queueless.hardware_simulation')]);} public function store(StorePrintOrderRequest $request,LockerAssignmentService $lockers,PickupCodeService $codes): RedirectResponse { try { [$order,$code]=DB::transaction(function()use($request,$lockers,$codes){$locker=$lockers->reserve();$code=$codes->generate();$file=$request->file('pdf');$order=PrintOrder::create(['public_reference'=>'QL-'.strtoupper(Str::random(10)),'email'=>$request->string('email'),'pickup_code_hash'=>$codes->hash($code),'pickup_code_last_four'=>substr($code,-4),'pdf_path'=>$file->store('print-orders','local'),'original_filename'=>$file->getClientOriginalName(),'locker_id'=>$locker->id,'status'=>PrintOrderStatus::Pending,'requested_pickup_at'=>$request->date('pickup_at'),'expires_at'=>$request->date('pickup_at')->addMinutes(config('queueless.expiry_grace_minutes'))]);$order->histories()->create(['new_status'=>PrintOrderStatus::Pending->value,'message'=>'Print request received.']);$lockers->attach($locker,$order);return[$order,$code];}); SimulatePrintJob::dispatch($order->id); return to_route('orders.show',$order->public_reference)->with('pickup_code',$code); } catch(RuntimeException $e){return back()->withErrors(['locker'=>$e->getMessage()])->withInput();} } public function show(string $reference): Response { $order=PrintOrder::with(['locker','histories'=>fn($q)=>$q->oldest()])->where('public_reference',$reference)->firstOrFail(); return Inertia::render('orders/show',['order'=>['reference'=>$order->public_reference,'status'=>$order->status->value,'locker'=>$order->locker->locker_number,'pickup_at'=>$order->requested_pickup_at->toIso8601String(),'expires_at'=>$order->expires_at->toIso8601String(),'filename'=>$order->original_filename,'code_last_four'=>$order->pickup_code_last_four,'history'=>$order->histories->map(fn($h)=>['status'=>$h->new_status,'message'=>$h->message,'at'=>$h->created_at->toIso8601String()])],'pickupCode'=>session('pickup_code')]); } public function lookup(Request $request): RedirectResponse { $query=$request->validate(['query'=>['required','string','max:50']])['query'];$order=PrintOrder::where('public_reference',strtoupper($query))->first()??PrintOrder::all()->first(fn($item)=>app(PickupCodeService::class)->verify($query,$item->pickup_code_hash));return $order?to_route('orders.show',$order->public_reference):back()->withErrors(['query'=>'No matching order was found.']);} }
